          sourceUrl2: "https://www.worldhistory.org/Polish-Lithuanian_Commonwealth/",
          sourceSnippet2: "World History Encyclopedia — Polish-Lithuanian Commonwealth",
          source3: "Polska.pl",
          sourceUrl3: "https://polska.pl/history/",
          sourceSnippet3: "Polska.pl — Union of Lublin 1569"
